<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import { RouterLink } from 'vue-router'
import { useI18n } from 'vue-i18n'
import { commerceApi, serviceApi, userApi } from '@/api/services'
import PageState from '@/shared/PageState.vue'
import Icon from '@/shared/Icon.vue'
import { bytes, date, money, orderStatus } from '@/shared/format'

const { t } = useI18n(); const loading = ref(true); const error = ref(''); const user = ref<any>({}); const subscribe = ref<any>({}); const notices = ref<any[]>([]); const orders = ref<any[]>([]); const traffic = ref<any[]>([])
const used = computed(() => Number(subscribe.value?.u || 0) + Number(subscribe.value?.d || 0)); const total = computed(() => Number(subscribe.value?.transfer_enable || user.value?.transfer_enable || 0)); const percent = computed(() => total.value ? Math.min(100, used.value / total.value * 100) : 0)
async function load() { loading.value = true; error.value = ''; try { const [u, s, n, o, tr] = await Promise.all([userApi.info(), userApi.subscribe(), serviceApi.notices().catch(() => []), commerceApi.orders().catch(() => []), serviceApi.traffic().catch(() => [])]); user.value = u || {}; subscribe.value = s || {}; notices.value = Array.isArray(n) ? n : []; orders.value = Array.isArray(o) ? o : o?.data || []; traffic.value = Array.isArray(tr) ? tr : tr?.data || [] } catch (e: any) { error.value = e.message } finally { loading.value = false } }
onMounted(load)
const chart = computed(() => { const values = traffic.value.slice(0, 7).reverse().map((item) => Number(item.u || 0) + Number(item.d || 0)); const max = Math.max(...values, 1); return values.concat(Array(7 - values.length).fill(0)).map((value, index) => `${index ? 'L' : 'M'} ${index * 110 + 10} ${140 - (value / max) * 105}`).join(' ') })
</script>

<template><PageState :loading="loading" :error="error" @retry="load"><div class="page-heading"><div><h1>{{ t('dashboard.greeting') }}</h1><p>{{ user.email || 'Misaka Network' }}</p></div></div><section class="subscription-hero"><div class="hero-plan"><span class="plan-icon"><Icon name="card" :size="30" /></span><div><small>{{ t('dashboard.subscription') }}</small><h2>{{ user.plan?.name || '暂无有效订阅' }}</h2><p v-if="user.expired_at">有效期至 {{ date(user.expired_at) }}</p></div></div><div class="hero-metric"><small>{{ t('dashboard.remaining') }}</small><strong>{{ bytes(Math.max(0, total - used)) }}</strong><div class="progress"><i :style="{ width: `${percent}%` }" /></div><p>{{ bytes(used) }} / {{ bytes(total) }}</p></div><div class="hero-metric"><small>{{ t('dashboard.reset') }}</small><strong class="date-value">{{ date(user.next_reset_at || user.expired_at) }}</strong><p>{{ percent.toFixed(1) }}% 已使用</p></div><div class="hero-actions"><RouterLink class="button secondary" to="/subscription">{{ t('dashboard.view') }}</RouterLink><RouterLink class="button primary" to="/plans">{{ t('dashboard.renew') }}</RouterLink></div></section><section class="quick-actions"><RouterLink to="/plans"><span class="action-icon blue"><Icon name="cart" /></span><div><strong>{{ t('dashboard.buy') }}</strong><small>选择最合适的套餐</small></div><Icon name="chevron" /></RouterLink><RouterLink to="/subscription"><span class="action-icon cyan"><Icon name="card" /></span><div><strong>{{ t('dashboard.import') }}</strong><small>一键导入订阅到客户端</small></div><Icon name="chevron" /></RouterLink><RouterLink to="/tickets"><span class="action-icon purple"><Icon name="ticket" /></span><div><strong>{{ t('dashboard.ticket') }}</strong><small>技术问题提交与跟进</small></div><Icon name="chevron" /></RouterLink></section><div class="dashboard-grid"><div class="dashboard-main"><section class="panel chart-panel"><header><h2>{{ t('dashboard.usage') }}</h2><span>近 7 天</span></header><svg class="usage-chart" viewBox="0 0 680 150" preserveAspectRatio="none"><defs><linearGradient id="area" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#1bb8d1" stop-opacity=".25"/><stop offset="1" stop-color="#1bb8d1" stop-opacity="0"/></linearGradient></defs><path :d="`${chart} L 670 140 L 10 140 Z`" fill="url(#area)"/><path :d="chart" fill="none" stroke="#13aeca" stroke-width="3"/><line v-for="y in [35,70,105,140]" :key="y" x1="10" x2="670" :y1="y" :y2="y" stroke="var(--border)" stroke-dasharray="3 5"/></svg><div class="chart-labels"><span v-for="day in ['周一','周二','周三','周四','周五','周六','周日']" :key="day">{{ day }}</span></div></section><section class="panel"><header><h2>{{ t('dashboard.recentOrders') }}</h2><RouterLink to="/orders">{{ t('common.more') }}</RouterLink></header><div class="table-wrap"><table><thead><tr><th>订单号</th><th>套餐</th><th>金额</th><th>状态</th><th>创建时间</th></tr></thead><tbody><tr v-for="order in orders.slice(0, 4)" :key="order.trade_no"><td><RouterLink :to="`/order/${order.trade_no}`">#{{ order.trade_no }}</RouterLink></td><td>{{ order.plan?.name || order.plan_name || '-' }}</td><td>{{ money(order.total_amount ?? order.total) }}</td><td><span class="status success">{{ orderStatus(order.status) }}</span></td><td>{{ date(order.created_at, true) }}</td></tr><tr v-if="!orders.length"><td colspan="5" class="empty-cell">{{ t('common.empty') }}</td></tr></tbody></table></div></section></div><aside class="panel notice-panel"><header><h2>{{ t('dashboard.notices') }}</h2><span>{{ notices.length }}</span></header><article v-for="notice in notices.slice(0, 6)" :key="notice.id"><i/><div><strong>{{ notice.title }}</strong><time>{{ date(notice.created_at, true) }}</time></div></article><p v-if="!notices.length" class="page-state">{{ t('common.empty') }}</p></aside></div></PageState></template>
